// auth/refresh-ping.ts
// Beacon Studio — Proactive Session Refresh
// Created: 2026-02-23 | Author: Echo (via worker)
// Tagged: KNOWN_ISSUE_2026_0223_BROWSER_AUTH | trustalign_review_pending

const REFRESH_INTERVAL_MS = 10 * 60 * 1000; // 10 min (safely under 15-min idle threshold)
const REFRESH_ENDPOINT = '/auth/refresh';

let refreshTimer: ReturnType<typeof setInterval> | null = null;

export function startRefreshPing(): void {
  if (refreshTimer) return; // prevent duplicate timers

  refreshTimer = setInterval(async () => {
    try {
      const res = await fetch(REFRESH_ENDPOINT, {
        method: 'POST',
        credentials: 'include', // ensures cookies are sent
      });

      if (!res.ok) {
        console.warn('[beacon:auth] Refresh ping failed:', res.status);
        // Graceful degradation — do not throw, let next cycle retry
      }
    } catch (err) {
      console.warn('[beacon:auth] Refresh ping network error:', err);
    }
  }, REFRESH_INTERVAL_MS);
}

export function stopRefreshPing(): void {
  if (refreshTimer) {
    clearInterval(refreshTimer);
    refreshTimer = null;
  }
}
```

### 📝 Integration — `auth/session-init.ts` (edit)

